import {
  useConsent,
  useScreen,
  useTransaction,
} from "@auth0/auth0-acul-react/consent";
import type { ConsentMembers } from "@auth0/auth0-acul-js/consent";
import type {
  ScreenMembersOnConsent,
  TransactionMembers,
} from "@auth0/auth0-acul-js";

import locales from "@/screens/consent/locales/es.json";
import { executeSafely } from "@/utils/helpers/executeSafely";

export const useConsentManager = () => {
  const consent: ConsentMembers = useConsent();
  const screen: ScreenMembersOnConsent = useScreen();
  const transaction: TransactionMembers = useTransaction();

  const { texts } = screen;

  const handleAccept = async (): Promise<void> => {
    executeSafely("User accepted consent", () => consent.accept());
  };

  const handleDeny = async (): Promise<void> => {
    executeSafely("User denied consent", () => consent.deny());
  };

  return {
    consent,
    screen,
    transaction,
    texts,
    locales,
    handleAccept,
    handleDeny,
  };
};
